parameters.jsCode:
const input = $json.body ?? $json;

const scheduledAt = input.scheduledAt ? new Date(input.scheduledAt) : null;
const validScheduledAt = scheduledAt && !Number.isNaN(scheduledAt.getTime());
const durationMinutes = Number(input.durationMinutes ?? 60);
const endAt = validScheduledAt
  ? new Date(scheduledAt.getTime() + durationMinutes * 60 * 1000)
  : null;

const alias = String(input.aliasAnonimo ?? 'Participante anónimo').trim();
const modalidad = input.modalidad ?? 'grupal';
const joinMode = input.joinMode ?? null;
const roomId = input.roomId ?? 'group:general';
const timezone = input.timezone ?? 'America/Guatemala';

return [{
  json: {
    request: input,
    shouldCreateCalendarEvent: modalidad === 'grupal' && joinMode === 'scheduled' && Boolean(validScheduledAt),
    reason: !validScheduledAt ? 'missing_or_invalid_scheduledAt' : modalidad !== 'grupal' ? 'not_group_modality' : joinMode !== 'scheduled' ? 'not_scheduled' : 'ready',
    calendar: {
      summary: 'Ataraxia - sesión grupal',
      description: [
        `Alias: ${alias}`,
        `Session ID: ${input.sessionId ?? 'n/a'}`,
        `Room: ${roomId}`,
        input.email ? `Email: ${input.email}` : null,
        input.phone ? `Phone: ${input.phone}` : null,
        '',
        'Nota: evento generado por n8n desde Ataraxia. No incluir nombres reales de participantes en el titulo.'
      ].filter(Boolean).join('\n'),
      start: validScheduledAt ? scheduledAt.toISOString() : null,
      end: endAt ? endAt.toISOString() : null,
      timezone,
      attendees: input.email ? [{ email: input.email }] : []
    }
  }
}];

